    fn load_test_data() -> Vec<(u32, u32)> {
        let parsed: Vec<[u32; 2]> = serde_json::from_str(DATASET).unwrap();
        parsed.into_iter().map(|[a, b]| (a, b)).collect()
    }

    #[test]
    fn test_recursive_cosiatec_compress() {
        let data = load_test_data();
        let tecs = recursive_cosiatec_compress(&data, true, 2);
        assert!(compression_stats(&tecs, &data).2 > 1.0);

        let dataset: HashSet<_> = data.into_iter().collect();
        let rebuilt: HashSet<_> = rebuild(tecs).into_iter().collect();
        assert_eq!(dataset, rebuilt);
    }

    #[test]
    fn test_cosiatec_compress() {
        let data = load_test_data();
        let tecs = cosiatec_compress(&data, true);
        assert!(compression_stats(&tecs, &data).2 > 1.0);

        let dataset: HashSet<_> = data.into_iter().collect();
        let rebuilt: HashSet<_> = rebuild(tecs).into_iter().collect();
        assert_eq!(dataset, rebuilt);
    }
